const getProvider = () => {

const rootData = inject('RiverState');

const init = async () => {
  await getNewData();
  // await getSectionCount();
  // getData();
  // getRemainingData();
}

watch(
  () => rootData,
  (val) => {
    state.ASSESSTYPE = val?.ASSESSTYPE || "MONTH";
    state.TIME = val?.TIME || "2024-12";
    state.WATER_CODE = val?.WATER_CODE || '';
    if (val?.selectType === 'day') {
      state.monitorType = 0;
    } else {
      state.monitorType = 1;
    }
    state.beginTime = val?.timeData[0];
    state.endTime = val?.timeData[1];
    init();
  },
  {
    immediate: true,
    deep: true
  }
)
};
